/**
 * Notification log model for tracking sent notification history.
 *
 * Each log entry records a notification that was processed by the
 * NotificationService, including delivery status and metadata.
 */

import type { NotificationChannel, NotificationType } from './notification.js';

export type DeliveryStatus = 'sent' | 'failed';

export interface NotificationLog {
  id: string;
  recipient: string;
  channel: NotificationChannel;
  type: NotificationType;
  subject: string;
  body: string;
  status: DeliveryStatus;
  timestamp: Date;
  metadata?: Record<string, unknown>;
}

export interface NotificationHistoryQuery {
  recipient?: string;
  channel?: NotificationChannel;
  type?: NotificationType;
  status?: DeliveryStatus;
  startDate?: Date;
  endDate?: Date;
}

/**
 * Repository for NotificationLog data access.
 *
 * Extends BaseRepository with notification-log-specific query methods.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { NotificationLog } from '../models/notification-log.js';
import type { NotificationChannel, NotificationType } from '../models/notification.js';
import type { DeliveryStatus } from '../models/notification-log.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLog> {
  constructor(db: Database) {
    super(db, 'notification_logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLog {
    return {
      id: record['id'] as string,
      recipient: record['recipient'] as string,
      channel: record['channel'] as NotificationChannel,
      type: record['type'] as NotificationType,
      subject: record['subject'] as string,
      body: record['body'] as string,
      status: record['status'] as DeliveryStatus,
      timestamp: new Date(record['timestamp'] as string),
      metadata: record['metadata'] ? JSON.parse(record['metadata'] as string) as Record<string, unknown> : undefined,
    };
  }

  protected toRecord(entity: NotificationLog): DatabaseRecord {
    return {
      id: entity.id,
      recipient: entity.recipient,
      channel: entity.channel,
      type: entity.type,
      subject: entity.subject,
      body: entity.body,
      status: entity.status,
      timestamp: entity.timestamp.toISOString(),
      metadata: entity.metadata ? JSON.stringify(entity.metadata) : '',
    };
  }

  findByRecipient(recipient: string): NotificationLog[] {
    return this.findAll((log) => log.recipient === recipient);
  }

  findByChannel(channel: NotificationChannel): NotificationLog[] {
    return this.findAll((log) => log.channel === channel);
  }

  findByType(type: NotificationType): NotificationLog[] {
    return this.findAll((log) => log.type === type);
  }

  findByStatus(status: DeliveryStatus): NotificationLog[] {
    return this.findAll((log) => log.status === status);
  }

  findByDateRange(startDate: Date, endDate: Date): NotificationLog[] {
    return this.findAll((log) => log.timestamp >= startDate && log.timestamp <= endDate);
  }
}

/**
 * Notification history service — logs and queries sent notifications.
 *
 * This service is used by the NotificationService to persist every
 * notification that passes through the system. It provides query
 * capabilities for retrieving notification history by various criteria.
 *
 * Depends on:
 * - NotificationLogRepository for data persistence
 */

import type { NotificationLog, NotificationHistoryQuery } from '../models/notification-log.js';
import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import type { NotificationChannel, NotificationType } from '../models/notification.js';
import type { DeliveryStatus } from '../models/notification-log.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateLogId(): string {
  return `nlog-${String(nextId++).padStart(4, '0')}`;
}

export function resetLogIdCounter(): void {
  nextId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');

  constructor(private repository: NotificationLogRepository) {}

  /**
   * Log a sent notification. Called by NotificationService after sending.
   */
  log(entry: Omit<NotificationLog, 'id'>): NotificationLog {
    const logEntry: NotificationLog = {
      id: generateLogId(),
      ...entry,
    };

    this.repository.save(logEntry);
    this.logger.info(`Logged notification ${logEntry.id} to ${logEntry.recipient} via ${logEntry.channel}`);
    return logEntry;
  }

  /**
   * Query notification history with flexible filters.
   */
  query(filters: NotificationHistoryQuery): NotificationLog[] {
    let results = this.repository.findAll();

    if (filters.recipient) {
      results = results.filter((log) => log.recipient === filters.recipient);
    }
    if (filters.channel) {
      results = results.filter((log) => log.channel === filters.channel);
    }
    if (filters.type) {
      results = results.filter((log) => log.type === filters.type);
    }
    if (filters.status) {
      results = results.filter((log) => log.status === filters.status);
    }
    if (filters.startDate) {
      results = results.filter((log) => log.timestamp >= filters.startDate!);
    }
    if (filters.endDate) {
      results = results.filter((log) => log.timestamp <= filters.endDate!);
    }

    return results;
  }

  /**
   * Get all logs for a specific recipient.
   */
  getByRecipient(recipient: string): NotificationLog[] {
    return this.repository.findByRecipient(recipient);
  }

  /**
   * Get all logs for a specific notification type.
   */
  getByType(type: NotificationType): NotificationLog[] {
    return this.repository.findByType(type);
  }

  /**
   * Get all logs for a specific channel.
   */
  getByChannel(channel: NotificationChannel): NotificationLog[] {
    return this.repository.findByChannel(channel);
  }

  /**
   * Get all logs within a date range.
   */
  getByDateRange(startDate: Date, endDate: Date): NotificationLog[] {
    return this.repository.findByDateRange(startDate, endDate);
  }

  /**
   * Get a single log entry by ID.
   */
  getById(id: string): NotificationLog | undefined {
    return this.repository.findById(id);
  }

  /**
   * Get total count of logged notifications.
   */
  count(): number {
    return this.repository.count();
  }
}

