import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('NotificationHistoryService', () => {
  let db: Database;
  let repository: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    repository = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(repository);
    resetLogIdCounter();
  });

  describe('log', () => {
    it('should log a notification and assign an ID', () => {
      const entry = historyService.log({
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'order-confirmation',
        subject: 'Order Confirmation',
        body: 'Your order has been placed.',
        status: 'sent',
        timestamp: new Date('2026-01-15T10:00:00Z'),
      });

      expect(entry.id).toBe('nlog-0001');
      expect(entry.recipient).toBe('alice@example.com');
      expect(entry.channel).toBe('email');
      expect(entry.type).toBe('order-confirmation');
      expect(entry.status).toBe('sent');
    });

    it('should generate sequential IDs', () => {
      const entry1 = historyService.log({
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'order-confirmation',
        subject: 'Order 1',
        body: 'Body 1',
        status: 'sent',
        timestamp: new Date(),
      });
      const entry2 = historyService.log({
        recipient: 'bob@example.com',
        channel: 'email',
        type: 'order-status-update',
        subject: 'Order 2',
        body: 'Body 2',
        status: 'sent',
        timestamp: new Date(),
      });

      expect(entry1.id).toBe('nlog-0001');
      expect(entry2.id).toBe('nlog-0002');
    });

    it('should persist to repository', () => {
      historyService.log({
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'order-confirmation',
        subject: 'Test',
        body: 'Test body',
        status: 'sent',
        timestamp: new Date(),
      });

      expect(repository.count()).toBe(1);
    });
  });

  describe('query', () => {
    beforeEach(() => {
      historyService.log({
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'order-confirmation',
        subject: 'Order Confirmed',
        body: 'Body',
        status: 'sent',
        timestamp: new Date('2026-01-15T10:00:00Z'),
      });
      historyService.log({
        recipient: 'bob@example.com',
        channel: 'webhook',
        type: 'order-status-update',
        subject: 'Status Update',
        body: 'Body',
        status: 'failed',
        timestamp: new Date('2026-01-16T10:00:00Z'),
      });
      historyService.log({
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'order-status-update',
        subject: 'Another Update',
        body: 'Body',
        status: 'sent',
        timestamp: new Date('2026-01-17T10:00:00Z'),
      });
    });

    it('should query by recipient', () => {
      const results = historyService.query({ recipient: 'alice@example.com' });
      expect(results).toHaveLength(2);
      expect(results.every((r) => r.recipient === 'alice@example.com')).toBe(true);
    });

    it('should query by channel', () => {
      const results = historyService.query({ channel: 'webhook' });
      expect(results).toHaveLength(1);
      expect(results[0]?.channel).toBe('webhook');
    });

    it('should query by type', () => {
      const results = historyService.query({ type: 'order-status-update' });
      expect(results).toHaveLength(2);
    });

    it('should query by status', () => {
      const results = historyService.query({ status: 'failed' });
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('bob@example.com');
    });

    it('should query by date range', () => {
      const results = historyService.query({
        startDate: new Date('2026-01-16T00:00:00Z'),
        endDate: new Date('2026-01-16T23:59:59Z'),
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('bob@example.com');
    });

    it('should combine multiple filters', () => {
      const results = historyService.query({
        recipient: 'alice@example.com',
        type: 'order-status-update',
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.subject).toBe('Another Update');
    });

    it('should return all when no filters provided', () => {
      const results = historyService.query({});
      expect(results).toHaveLength(3);
    });
  });

  describe('convenience methods', () => {
    beforeEach(() => {
      historyService.log({
        recipient: 'alice@example.com',
        channel: 'email',
        type: 'order-confirmation',
        subject: 'Test',
        body: 'Body',
        status: 'sent',
        timestamp: new Date('2026-01-15T10:00:00Z'),
      });
      historyService.log({
        recipient: 'bob@example.com',
        channel: 'webhook',
        type: 'order-status-update',
        subject: 'Test 2',
        body: 'Body',
        status: 'sent',
        timestamp: new Date('2026-01-16T10:00:00Z'),
      });
    });

    it('should get by recipient', () => {
      expect(historyService.getByRecipient('alice@example.com')).toHaveLength(1);
    });

    it('should get by type', () => {
      expect(historyService.getByType('order-confirmation')).toHaveLength(1);
    });

    it('should get by channel', () => {
      expect(historyService.getByChannel('webhook')).toHaveLength(1);
    });

    it('should get by date range', () => {
      const results = historyService.getByDateRange(
        new Date('2026-01-15T00:00:00Z'),
        new Date('2026-01-15T23:59:59Z'),
      );
      expect(results).toHaveLength(1);
    });

    it('should get by ID', () => {
      const entry = historyService.getById('nlog-0001');
      expect(entry).toBeDefined();
      expect(entry?.recipient).toBe('alice@example.com');
    });

    it('should return undefined for unknown ID', () => {
      expect(historyService.getById('nlog-9999')).toBeUndefined();
    });

    it('should count entries', () => {
      expect(historyService.count()).toBe(2);
    });
  });

  describe('integration with NotificationService', () => {
    let eventBus: EventBus;
    let notificationService: NotificationService;

    beforeEach(() => {
      eventBus = new EventBus();
      statusChangeCallbacks.clear();
      notificationService = new NotificationService(eventBus);
      notificationService.setHistoryService(historyService);
      resetNotificationIdCounter();
    });

    it('should log notifications sent via order:created events', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
          ],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(historyService.count()).toBe(1);
      const logs = historyService.getByRecipient('alice@example.com');
      expect(logs).toHaveLength(1);
      expect(logs[0]?.type).toBe('order-confirmation');
      expect(logs[0]?.channel).toBe('email');
      expect(logs[0]?.status).toBe('sent');
      expect(logs[0]?.subject).toContain('Order Confirmation');
    });

    it('should log notifications sent via status change callbacks', () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      statusChangeCallbacks.notify(event);

      expect(historyService.count()).toBe(1);
      const logs = historyService.query({ type: 'order-status-update' });
      expect(logs).toHaveLength(1);
      expect(logs[0]?.recipient).toBe('user-1');
      expect(logs[0]?.status).toBe('sent');
    });

    it('should log multiple notifications and query them', async () => {
      const orderCreatedEvent: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [
            { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
          ],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(orderCreatedEvent);

      statusChangeCallbacks.notify({
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 10,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      });

      expect(historyService.count()).toBe(2);
      expect(historyService.getByType('order-confirmation')).toHaveLength(1);
      expect(historyService.getByType('order-status-update')).toHaveLength(1);
    });
  });
});

